def solve(grid):
    import numpy as np
    from collections import defaultdict

    grid = np.array(grid)
    H, W = grid.shape
    bg = 7

    non_bg = []
    for r in range(H):
        for c in range(W):
            if grid[r][c] != bg:
                non_bg.append((r, c, grid[r][c]))

    if not non_bg:
        return grid.tolist()

    best_direction = None
    best_segments = None

    for direction in ['antidiag', 'diag', 'horizontal', 'vertical']:
        groups = defaultdict(list)
        for r, c, color in non_bg:
            if direction == 'antidiag':
                key = r + c
            elif direction == 'diag':
                key = r - c
            elif direction == 'horizontal':
                key = r
            elif direction == 'vertical':
                key = c
            groups[key].append((r, c, color))

        valid = True
        segments = []
        for key, cells in sorted(groups.items()):
            cells_sorted = sorted(cells)
            if direction == 'horizontal':
                cols = [c for r, c, color in cells_sorted]
                if cols != list(range(min(cols), max(cols)+1)):
                    valid = False
                    break
            elif direction == 'vertical':
                rows = [r for r, c, color in cells_sorted]
                if rows != list(range(min(rows), max(rows)+1)):
                    valid = False
                    break
            else:
                rows = sorted([r for r, c, color in cells_sorted])
                if rows != list(range(min(rows), max(rows)+1)):
                    valid = False
                    break

            colors = set(color for r, c, color in cells_sorted)
            if len(colors) != 1:
                valid = False
                break

            segments.append((key, cells_sorted, list(colors)[0]))

        if valid and len(segments) >= 2:
            best_direction = direction
            best_segments = segments
            break

    if best_segments is None:
        return grid.tolist()

    segments_info = []
    for key, cells, color in best_segments:
        cells_rc = [(r, c) for r, c, _ in cells]
        length = len(cells_rc)
        if best_direction in ['antidiag', 'diag', 'vertical']:
            ep1 = min(cells_rc, key=lambda x: x[0])
            ep2 = max(cells_rc, key=lambda x: x[0])
        else:
            ep1 = min(cells_rc, key=lambda x: x[1])
            ep2 = max(cells_rc, key=lambda x: x[1])
        segments_info.append({
            'key': key, 'cells': cells_rc, 'color': color,
            'length': length, 'ep1': ep1, 'ep2': ep2
        })

    def is_collinear(points):
        if len(points) <= 2:
            return True
        r0, c0 = points[0]
        r1, c1 = points[1]
        for r, c in points[2:]:
            if (r1-r0)*(c-c0) - (c1-c0)*(r-r0) != 0:
                return False
        return True

    ep1s = [s['ep1'] for s in segments_info]
    ep2s = [s['ep2'] for s in segments_info]

    anchor_is_ep1 = is_collinear(ep1s)

    n = len(segments_info)
    mid_idx = n // 2
    target_length = segments_info[mid_idx]['length']

    output = np.full_like(grid, bg)

    for seg in segments_info:
        anchor = seg['ep1'] if anchor_is_ep1 else seg['ep2']
        color = seg['color']

        if best_direction == 'antidiag':
            if anchor_is_ep1:
                dr, dc = 1, -1
            else:
                dr, dc = -1, 1
        elif best_direction == 'diag':
            if anchor_is_ep1:
                dr, dc = 1, 1
            else:
                dr, dc = -1, -1
        elif best_direction == 'horizontal':
            if anchor_is_ep1:
                dr, dc = 0, 1
            else:
                dr, dc = 0, -1
        elif best_direction == 'vertical':
            if anchor_is_ep1:
                dr, dc = 1, 0
            else:
                dr, dc = -1, 0

        r, c = anchor
        for i in range(target_length):
            nr, nc = r + i*dr, c + i*dc
            if 0 <= nr < H and 0 <= nc < W:
                output[nr][nc] = color

    return output.tolist()

